// formatCurrency.test.js

// Mock implementation for reference (you would import your actual function)
function formatCurrency(cents, currency) {
  // Validate currency code
  const supportedCurrencies = ['USD', 'EUR', 'GBP', 'JPY'];
  if (!supportedCurrencies.includes(currency)) {
    throw new Error(`Unsupported currency code: ${currency}`);
  }

  // Handle floating-point precision by rounding
  const roundedCents = Math.round(cents);

  // Convert cents to main currency unit
  const amount = roundedCents / 100;

  // Currency symbols mapping
  const currencySymbols = {
    'USD': '$',
    'EUR': '€',
    'GBP': '£',
    'JPY': '¥'
  };

  // Format based on currency (JPY doesn't use decimal places)
  if (currency === 'JPY') {
    return `${currencySymbols[currency]}${roundedCents}`;
  }

  return `${currencySymbols[currency]}${amount.toFixed(2)}`;
}

describe('formatCurrency', () => {
  describe('Basic functionality', () => {
    test('should format positive cents correctly to USD', () => {
      expect(formatCurrency(1999, 'USD')).toBe('$19.99');
    });

    test('should format zero cents correctly', () => {
      expect(formatCurrency(0, 'USD')).toBe('$0.00');
    });

    test('should handle negative values correctly', () => {
      expect(formatCurrency(-1500, 'USD')).toBe('$-15.00');
      expect(formatCurrency(-99, 'EUR')).toBe('€-0.99');
    });
  });

  describe('Large values', () => {
    test('should handle values over 1 billion cents', () => {
      expect(formatCurrency(150000000000, 'USD')).toBe('$1500000000.00'); // 1.5 billion dollars
      expect(formatCurrency(100000000001, 'GBP')).toBe('£1000000000.01'); // Over 1 billion pounds
    });
  });

  describe('Currency support', () => {
    test('should format different supported currencies correctly', () => {
      expect(formatCurrency(1000, 'USD')).toBe('$10.00');
      expect(formatCurrency(1000, 'EUR')).toBe('€10.00');
      expect(formatCurrency(1000, 'GBP')).toBe('£10.00');
    });

    test('should handle JPY currency without decimal places', () => {
      expect(formatCurrency(1000, 'JPY')).toBe('¥1000');
      expect(formatCurrency(150, 'JPY')).toBe('¥150');
    });

    test('should throw error for unsupported currency codes', () => {
      expect(() => formatCurrency(1000, 'CAD')).toThrow('Unsupported currency code: CAD');
      expect(() => formatCurrency(500, 'XYZ')).toThrow('Unsupported currency code: XYZ');
      expect(() => formatCurrency(100, '')).toThrow('Unsupported currency code: ');
    });
  });

  describe('Floating-point precision', () => {
    test('should handle floating-point inputs by rounding', () => {
      expect(formatCurrency(1999.4, 'USD')).toBe('$19.99');
      expect(formatCurrency(1999.6, 'USD')).toBe('$20.00');
      expect(formatCurrency(1234.5, 'EUR')).toBe('€12.35');
    });

    test('should maintain precision for exact cent values', () => {
      expect(formatCurrency(1, 'USD')).toBe('$0.01');
      expect(formatCurrency(99, 'GBP')).toBe('£0.99');
      expect(formatCurrency(12345, 'EUR')).toBe('€123.45');
    });
  });

  describe('Edge cases', () => {
    test('should handle very small negative values', () => {
      expect(formatCurrency(-1, 'USD')).toBe('$-0.01');
    });

    test('should handle currency code case sensitivity', () => {
      // This test assumes the function is case-sensitive
      expect(() => formatCurrency(1000, 'usd')).toThrow('Unsupported currency code: usd');
    });
  });
});
